import { useState, useEffect, useRef, useCallback } from 'react';
import { toast } from 'sonner';
import { AlertTriangle, Clock, MapPin, Activity, Filter, Wifi, WifiOff, Loader2, Fingerprint } from 'lucide-react';
import { useIncidentCase } from '@/contexts/IncidentCaseContext';
import { createIncidentFromHotspot } from '@/data/incidentCases';

/* ─── Types (mirrored from API) ─── */
interface Hotspot {
  id: string;
  name: string;
  x: number;
  y: number;
  severity: 'critical' | 'high' | 'medium';
  vectors: number;
  voipNodes: number;
  arrests: number;
  firs: number;
  description: string;
  state: string;
}

interface Incident {
  id: string;
  time: string;
  incidentId: string;
  type: string;
  location: string;
  status: string;
  severity: 'CRITICAL' | 'HIGH' | 'MEDIUM';
}

interface LedgerEntry {
  id: string;
  time: string;
  message: string;
  color: string;
}

type SyncStatus = 'connecting' | 'live' | 'error';

